import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.B45ElpZ1.js";const u=JSON.parse('{"title":"Broker Setup","description":"Configure MCP-backed broker workflows for Groww and Zerodha Kite in tradecli.","frontmatter":{"title":"Broker Setup","description":"Configure MCP-backed broker workflows for Groww and Zerodha Kite in tradecli.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/getting-started/broker-setup"}]]},"headers":[],"relativePath":"getting-started/broker-setup.md","filePath":"getting-started/broker-setup.md"}'),i={name:"getting-started/broker-setup.md"};function s(n,e,l,c,d,p){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="broker-setup" tabindex="-1">Broker Setup <a class="header-anchor" href="#broker-setup" aria-label="Permalink to &quot;Broker Setup&quot;">​</a></h1><p>Broker access is configured through the normal local setup path. The goal is not to hand credentials to a hosted service; it is to let <code>tradecli</code> coordinate local broker/browser sessions when a workflow needs account context.</p><div class="tip custom-block"><p class="custom-block-title">Start here</p><p>Run <code>tradecli setup</code> first. It creates the local config, checks the broker gateway, verifies browser prerequisites, and prompts for available fixes when supported auth is missing or expired.</p></div><h2 id="supported-brokers" tabindex="-1">Supported brokers <a class="header-anchor" href="#supported-brokers" aria-label="Permalink to &quot;Supported brokers&quot;">​</a></h2><p>Current MCP-backed broker flows focus on:</p><ul><li><strong>Groww MCP</strong> for holdings, watchlists, screeners, and account context.</li><li><strong>Zerodha Kite MCP</strong> for holdings, positions, margins, historical data, and account context.</li></ul><p>Broker behavior is intentionally local and explicit. Agents can prepare analysis and surface broker context, but actions that move money still require user approval at the broker surface.</p><h2 id="groww-connection" tabindex="-1">Groww connection <a class="header-anchor" href="#groww-connection" aria-label="Permalink to &quot;Groww connection&quot;">​</a></h2><p>Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>If Groww auth is missing or expired, setup can prompt to repair it. You can also run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fix</span></span></code></pre></div><p>Doctor uses the same environment checks and can re-acquire Groww auth when the fix path is available.</p><h2 id="zerodha-kite-connection" tabindex="-1">Zerodha Kite connection <a class="header-anchor" href="#zerodha-kite-connection" aria-label="Permalink to &quot;Zerodha Kite connection&quot;">​</a></h2><p>Kite does not keep the same persistent token shape as Groww. After setup, Kite login happens interactively the first time a Kite workflow needs it.</p><p>Use <code>tradecli setup</code> to make sure the local broker gateway and browser profile are ready before that first-use login.</p><h2 id="token-refresh-and-reauth" tabindex="-1">Token refresh and reauth <a class="header-anchor" href="#token-refresh-and-reauth" aria-label="Permalink to &quot;Token refresh and reauth&quot;">​</a></h2><ul><li>Run <code>tradecli doctor</code> when broker-aware workflows behave unexpectedly.</li><li>Run <code>tradecli doctor --fix</code> when you want tradecli to prompt for safe repairs.</li><li>Expect Groww to support a repair prompt when auth is missing or expired.</li><li>Expect Kite to ask for login again on first use or after the broker session expires.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>If setup or doctor cannot repair the broker path:</p><ul><li>Confirm Chrome is installed and usable.</li><li>Re-run <code>tradecli setup</code> after changing shell environment variables or model credentials.</li><li>Launch <code>tradecli</code>, choose a broker-aware workflow, and complete any first-use broker login prompt.</li><li>If you&#39;re still stuck, email <a href="mailto:contact@tradecli.in" target="_blank" rel="noreferrer">contact@tradecli.in</a>.</li></ul>',21)])])}const k=t(i,[["render",s]]);export{u as __pageData,k as default};
